using Microsoft.AspNetCore.Identity.EntityFrameworkCore;
using Microsoft.EntityFrameworkCore;
using VetClinic.Data.Models;

namespace VetClinic.Data;

public class ApplicationDbContext(DbContextOptions<ApplicationDbContext> options) : IdentityDbContext<ApplicationUser>(options)
{
    public DbSet<Owner> Owners => Set<Owner>();
    public DbSet<Pet> Pets => Set<Pet>();
    public DbSet<Appointment> Appointments => Set<Appointment>();
    public DbSet<Treatment> Treatments => Set<Treatment>();
    public DbSet<Invoice> Invoices => Set<Invoice>();
    public DbSet<Payment> Payments => Set<Payment>();

    protected override void OnModelCreating(ModelBuilder builder)
    {
        base.OnModelCreating(builder);

        // Owner -> Pets: cascade delete
        builder.Entity<Pet>()
            .HasOne(p => p.Owner)
            .WithMany(o => o.Pets)
            .HasForeignKey(p => p.OwnerId)
            .OnDelete(DeleteBehavior.Cascade);

        // Pet -> Appointments: cascade delete
        builder.Entity<Appointment>()
            .HasOne(a => a.Pet)
            .WithMany(p => p.Appointments)
            .HasForeignKey(a => a.PetId)
            .OnDelete(DeleteBehavior.Cascade);

        // Pet -> Treatments: cascade delete
        builder.Entity<Treatment>()
            .HasOne(t => t.Pet)
            .WithMany(p => p.Treatments)
            .HasForeignKey(t => t.PetId)
            .OnDelete(DeleteBehavior.Cascade);

        // Treatment -> Appointment: optional, set null
        builder.Entity<Treatment>()
            .HasOne(t => t.Appointment)
            .WithMany()
            .HasForeignKey(t => t.AppointmentId)
            .OnDelete(DeleteBehavior.SetNull);

        // Owner -> Invoices: restrict delete
        builder.Entity<Invoice>()
            .HasOne(i => i.Owner)
            .WithMany(o => o.Invoices)
            .HasForeignKey(i => i.OwnerId)
            .OnDelete(DeleteBehavior.Restrict);

        // Invoice -> Payments: restrict delete
        builder.Entity<Payment>()
            .HasOne(p => p.Invoice)
            .WithMany(i => i.Payments)
            .HasForeignKey(p => p.InvoiceId)
            .OnDelete(DeleteBehavior.Restrict);

        builder.Entity<Invoice>()
            .Property(i => i.TotalAmount).HasColumnType("decimal(18,2)");
        builder.Entity<Invoice>()
            .Property(i => i.PaidAmount).HasColumnType("decimal(18,2)");
        builder.Entity<Payment>()
            .Property(p => p.Amount).HasColumnType("decimal(18,2)");
        builder.Entity<Treatment>()
            .Property(t => t.Cost).HasColumnType("decimal(18,2)");
        builder.Entity<Pet>()
            .Property(p => p.Weight).HasColumnType("decimal(18,2)");
    }
}

builder.Services.AddIdentityCore<ApplicationUser>(options =>
    {
        options.SignIn.RequireConfirmedAccount = false;
        options.Password.RequiredLength = 6;
        options.Stores.SchemaVersion = IdentitySchemaVersions.Version3;
    })

