@page "/patients"
@attribute [Authorize]
@rendermode InteractiveServer
@using Microsoft.AspNetCore.Authorization
@using Microsoft.EntityFrameworkCore
@inject VetClinic.Data.ApplicationDbContext DbContext
@inject NavigationManager Navigation

<PageTitle>Patients</PageTitle>

<div class="d-flex justify-content-between align-items-center mb-4">
    <h1>Patients</h1>
    <a href="/patients/new" class="btn btn-primary">Add Patient</a>
</div>

<div class="row mb-3">
    <div class="col-md-6">
        <input type="text" class="form-control" placeholder="Search by name or species..."
               @bind="searchTerm" @bind:event="oninput" @bind:after="FilterPatients" />
    </div>
</div>

@if (filteredPets == null)
{
    <p>Loading...</p>
}
else if (!filteredPets.Any())
{
    <p class="text-muted">No patients found.</p>
}
else
{
    <div class="table-responsive">
        <table class="table table-striped table-hover">
            <thead>
                <tr>
                    <th @onclick="() => SortBy(nameof(Pet.Name))" style="cursor:pointer">Name ↕</th>
                    <th @onclick="() => SortBy(nameof(Pet.Species))" style="cursor:pointer">Species ↕</th>
                    <th>Breed</th>
                    <th>Owner</th>
                    <th>Date of Birth</th>
                    <th>Actions</th>
                </tr>
            </thead>
            <tbody>
                @foreach (var pet in filteredPets)
                {
                    <tr>
                        <td><a href="/patients/@pet.Id">@pet.Name</a></td>
                        <td>@pet.Species</td>
                        <td>@pet.Breed</td>
                        <td>@pet.Owner?.FirstName @pet.Owner?.LastName</td>
