    private bool sortAscending = true;

    protected override async Task OnInitializedAsync()
    {
        allPets = await DbContext.Pets.Include(p => p.Owner).ToListAsync();
        FilterPatients();
    }

    private void FilterPatients()
    {
        if (allPets == null) return;

        var query = allPets.AsEnumerable();

        if (!string.IsNullOrWhiteSpace(searchTerm))
        {
            var term = searchTerm.ToLower();
            query = query.Where(p =>
                (p.Name?.ToLower().Contains(term) ?? false) ||
                (p.Species?.ToLower().Contains(term) ?? false));
        }

        query = sortColumn switch
        {
            nameof(Pet.Species) => sortAscending ? query.OrderBy(p => p.Species) : query.OrderByDescending(p => p.Species),
            _ => sortAscending ? query.OrderBy(p => p.Name) : query.OrderByDescending(p => p.Name)
        };

        filteredPets = query.ToList();
