                                        <InputDate class="form-control" @bind-Value="newTreatment.TreatmentDate" />
                                    </div>
                                    <div class="col-md-4 mb-2">
                                        <label class="form-label">Veterinarian</label>
                                        <InputText class="form-control" @bind-Value="newTreatment.VeterinarianName" />
                                    </div>
                                    <div class="col-md-4 mb-2">
                                        <label class="form-label">Cost</label>
                                        <InputNumber class="form-control" @bind-Value="newTreatment.Cost" />
                                    </div>
                                </div>
                                <div class="mb-2">
                                    <label class="form-label">Description</label>
                                    <InputTextArea class="form-control" @bind-Value="newTreatment.Description" />
                                </div>
                                <div class="mb-2">
                                    <label class="form-label">Medication</label>
                                    <InputText class="form-control" @bind-Value="newTreatment.Medication" />
                                </div>
                                <button type="submit" class="btn btn-success btn-sm">Save Treatment</button>
                                <button type="button" class="btn btn-outline-secondary btn-sm" @onclick="ToggleTreatmentForm">Cancel</button>
                            </EditForm>
                        </div>
                    }

                    @if (treatments?.Any() == true)
                    {
                        <table class="table table-sm">
                            <thead>
                                <tr><th>Date</th><th>Description</th><th>Medication</th><th>Vet</th><th>Cost</th></tr>
                            </thead>
                            <tbody>
                                @foreach (var t in treatments)
                                {
                                    <tr>
                                        <td>@t.TreatmentDate.ToString("MM/dd/yyyy")</td>
                                        <td>@t.Description</td>
                                        <td>@(t.Medication ?? "N/A")</td>
                                        <td>@(t.VeterinarianName ?? "N/A")</td>
                                        <td>@(t.Cost > 0 ? t.Cost.ToString("C") : "N/A")</td>
                                    </tr>
                                }
                            </tbody>
                        </table>
                    }
                    else
                    {
                        <p class="text-muted mb-0">No treatment records.</p>
                    }
                </div>
            </div>
        </div>
    </div>
}

@code {
    [Parameter] public int Id { get; set; }

    private Pet? pet;
    private List<Appointment>? upcomingAppointments;
    private List<Treatment>? treatments;
    private bool showTreatmentForm;
    private Treatment newTreatment = new();
    private string? treatmentError;

    protected override async Task OnInitializedAsync()
    {
        pet = await DbContext.Pets.Include(p => p.Owner).FirstOrDefaultAsync(p => p.Id == Id);

        if (pet != null)
        {
            upcomingAppointments = await DbContext.Appointments
                .Where(a => a.PetId == Id && a.ScheduledAt >= DateTime.Now && a.Status != AppointmentStatus.Cancelled)
                .OrderBy(a => a.ScheduledAt)
                .ToListAsync();

            treatments = await DbContext.Treatments
                .Where(t => t.PetId == Id)
                .OrderByDescending(t => t.TreatmentDate)
                .ToListAsync();
        }
    }

    private void ToggleTreatmentForm()
    {
        showTreatmentForm = !showTreatmentForm;
        if (showTreatmentForm)
        {
            newTreatment = new Treatment { TreatmentDate = DateTime.Today, PetId = Id };
        }
    }

    private async Task AddTreatment()
    {
        try
        {
            newTreatment.PetId = Id;
            newTreatment.CreatedAt = DateTime.UtcNow;
            DbContext.Treatments.Add(newTreatment);
            await DbContext.SaveChangesAsync();
            treatments?.Insert(0, newTreatment);
            showTreatmentForm = false;
            newTreatment = new Treatment();
        }
        catch (Exception ex)
        {
            treatmentError = $"Error saving treatment: {ex.Message}";
        }
    }

    private string GetStatusBadge(AppointmentStatus status) => status switch
    {
        AppointmentStatus.Scheduled => "bg-primary",
        AppointmentStatus.Completed => "bg-success",
        AppointmentStatus.Cancelled => "bg-danger",
        _ => "bg-secondary"
    };
}

