@page "/appointments"
@attribute [Authorize]
@rendermode InteractiveServer
@using Microsoft.AspNetCore.Authorization
@using Microsoft.EntityFrameworkCore
@inject VetClinic.Data.ApplicationDbContext DbContext
@inject NavigationManager Navigation

<PageTitle>Appointments - Weekly Calendar</PageTitle>

<div class="d-flex justify-content-between align-items-center mb-4">
    <h1>Appointments</h1>
    <a href="/appointments/new" class="btn btn-primary">New Appointment</a>
</div>

<div class="d-flex align-items-center gap-3 mb-3">
    <button class="btn btn-outline-secondary" @onclick="PreviousWeek">← Previous</button>
    <h5 class="mb-0">@weekStart.ToString("MMM dd") - @weekEnd.ToString("MMM dd, yyyy")</h5>
    <button class="btn btn-outline-secondary" @onclick="NextWeek">Next →</button>
    <button class="btn btn-outline-primary" @onclick="GoToToday">Today</button>
</div>

<div class="mb-2">
    <span class="badge bg-primary me-1">Scheduled</span>
    <span class="badge bg-success me-1">Completed</span>
    <span class="badge bg-danger me-1">Cancelled</span>
</div>

<div class="table-responsive">
    <table class="table table-bordered table-sm" style="table-layout: fixed;">
        <thead class="table-light">
            <tr>
                <th style="width:80px;">Time</th>
                @for (int d = 0; d < 7; d++)
                {
                    var day = weekStart.AddDays(d);
                    <th class="text-center @(day.Date == DateTime.Today ? "table-info" : "")">
                        @day.ToString("ddd MM/dd")
                    </th>
                }
            </tr>
        </thead>
        <tbody>
            @for (int slot = 0; slot < timeSlots.Count; slot++)
            {
                var time = timeSlots[slot];
                <tr>
                    <td class="text-nowrap small">@time.ToString("hh:mm tt")</td>
                    @for (int d = 0; d < 7; d++)
                    {
                        var day = weekStart.AddDays(d);
                        var slotStart = day.Add(time);
                        var appt = GetAppointmentAt(slotStart);
                        if (appt != null)
                        {
                            <td class="p-1 @GetCellClass(appt.Status)" style="cursor:pointer;" @onclick="() => Navigation.NavigateTo($\"/appointments/{appt.Id}/edit\")">
                                <small><strong>@appt.Pet?.Name</strong><br/>@appt.Reason</small>
                            </td>
                        }
                        else
                        {
                            <td class="p-1" style="cursor:pointer;" @onclick="() => NavigateToNewSlot(slotStart)">
                                &nbsp;
                            </td>
                        }
                    }
                </tr>
            }
        </tbody>
    </table>
</div>

@code {
    private DateTime weekStart;
    private DateTime weekEnd;
    private List<TimeSpan> timeSlots = new();
    private List<Appointment> weekAppointments = new();

    protected override async Task OnInitializedAsync()
    {
        // Generate 30-min slots from 8am to 6pm
        for (int h = 8; h < 18; h++)
        {
            timeSlots.Add(new TimeSpan(h, 0, 0));
            timeSlots.Add(new TimeSpan(h, 30, 0));
        }

        GoToToday();
        await LoadAppointments();
    }

    private void GoToToday()
    {
        var today = DateTime.Today;
        int diff = (int)today.DayOfWeek - (int)DayOfWeek.Monday;
        if (diff < 0) diff += 7;
        weekStart = today.AddDays(-diff);
        weekEnd = weekStart.AddDays(6);
    }

    private async Task PreviousWeek()
    {
        weekStart = weekStart.AddDays(-7);
        weekEnd = weekStart.AddDays(6);
        await LoadAppointments();
    }

    private async Task NextWeek()
    {
        weekStart = weekStart.AddDays(7);
        weekEnd = weekStart.AddDays(6);
        await LoadAppointments();
    }

    private async Task LoadAppointments()
    {
        var end = weekEnd.AddDays(1);
        weekAppointments = await DbContext.Appointments
            .Include(a => a.Pet)
            .Where(a => a.ScheduledAt >= weekStart && a.ScheduledAt < end)
            .ToListAsync();
    }

    private Appointment? GetAppointmentAt(DateTime slotStart)
    {
        return weekAppointments.FirstOrDefault(a =>
            a.ScheduledAt >= slotStart && a.ScheduledAt < slotStart.AddMinutes(30));
    }

    private string GetCellClass(AppointmentStatus status) => status switch
    {
        AppointmentStatus.Scheduled => "table-primary",
        AppointmentStatus.Completed => "table-success",
        AppointmentStatus.Cancelled => "table-danger",
        _ => ""
    };

    private void NavigateToNewSlot(DateTime slotStart)
    {
        Navigation.NavigateTo($"/appointments/new?date={slotStart:yyyy-MM-ddTHH:mm}");
    }
}

@page "/appointments/new"
@page "/appointments/{Id:int}/edit"
@attribute [Authorize]
@rendermode InteractiveServer
@using Microsoft.AspNetCore.Authorization
@using Microsoft.EntityFrameworkCore
@inject VetClinic.Data.ApplicationDbContext DbContext
@inject NavigationManager Navigation

<PageTitle>@(Id.HasValue ? "Edit Appointment" : "New Appointment")</PageTitle>

<h1 class="mb-4">@(Id.HasValue ? "Edit Appointment" : "New Appointment")</h1>

@if (errorMessage != null)
{
    <div class="alert alert-danger">@errorMessage</div>
}
@if (successMessage != null)
{
    <div class="alert alert-success">@successMessage</div>
}

@if (appointment != null)
{
    <EditForm Model="appointment" OnValidSubmit="HandleSubmit" FormName="appointmentForm">
        <DataAnnotationsValidator />
        <ValidationSummary class="text-danger" />

        <div class="row">
            <div class="col-md-6 mb-3">
                <label class="form-label">Pet</label>
                <InputSelect class="form-select" @bind-Value="appointment.PetId">
                    <option value="0">-- Select Pet --</option>
                    @if (pets != null)
                    {
                        @foreach (var pet in pets)
                        {
                            <option value="@pet.Id">@pet.Name (@pet.Owner?.LastName)</option>
                        }
                    }
                </InputSelect>
            </div>
            <div class="col-md-3 mb-3">
                <label class="form-label">Date &amp; Time</label>
                <InputDate class="form-control" Type="InputDateType.DateTimeLocal" @bind-Value="appointment.ScheduledAt" />
            </div>
            <div class="col-md-3 mb-3">
                <label class="form-label">Duration (minutes)</label>
                <InputNumber class="form-control" @bind-Value="appointment.DurationMinutes" />
            </div>
        </div>

        <div class="row">
            <div class="col-md-6 mb-3">
                <label class="form-label">Reason</label>
                <InputText class="form-control" @bind-Value="appointment.Reason" />
            </div>
            <div class="col-md-6 mb-3">
                <label class="form-label">Status</label>
                <InputSelect class="form-select" @bind-Value="appointment.Status">
                    @foreach (var status in Enum.GetValues<AppointmentStatus>())
                    {
                        <option value="@status">@status</option>
                    }
                </InputSelect>
            </div>
        </div>

        <div class="mb-3">
            <label class="form-label">Notes</label>
            <InputTextArea class="form-control" rows="3" @bind-Value="appointment.Notes" />
        </div>

        @if (conflictWarning != null)
        {
            <div class="alert alert-warning">@conflictWarning</div>
        }

        <div class="d-flex gap-2">
            <button type="submit" class="btn btn-primary">@(Id.HasValue ? "Update" : "Create") Appointment</button>
            @if (Id.HasValue && appointment.Status != AppointmentStatus.Cancelled)
            {
                <button type="button" class="btn btn-danger" @onclick="CancelAppointment">Cancel Appointment</button>
            }
            <a href="/appointments" class="btn btn-outline-secondary">Back to Calendar</a>
        </div>
    </EditForm>
}

@code {
    [Parameter] public int? Id { get; set; }
    [SupplyParameterFromQuery(Name = "date")] public string? DateParam { get; set; }

    private Appointment appointment = new() { DurationMinutes = 30, Status = AppointmentStatus.Scheduled };
    private List<Pet>? pets;
    private string? errorMessage;
    private string? successMessage;
    private string? conflictWarning;

    protected override async Task OnInitializedAsync()
    {
        pets = await DbContext.Pets.Include(p => p.Owner).OrderBy(p => p.Name).ToListAsync();

        if (Id.HasValue)
        {
            var existing = await DbContext.Appointments.FindAsync(Id.Value);
            if (existing == null)
            {
                errorMessage = "Appointment not found.";
                return;
            }
            appointment = existing;
        }
        else if (!string.IsNullOrEmpty(DateParam) && DateTime.TryParse(DateParam, out var parsedDate))
        {
            appointment.ScheduledAt = parsedDate;
        }
    }

    private async Task HandleSubmit()
    {
        errorMessage = null;
        successMessage = null;
        conflictWarning = null;

        // Validate no scheduling conflicts
        var endTime = appointment.ScheduledAt.AddMinutes(appointment.DurationMinutes);
        var hasConflict = await DbContext.Appointments
            .AnyAsync(a => a.Id != (Id ?? 0)
                && a.Status != AppointmentStatus.Cancelled
                && a.ScheduledAt < endTime
                && a.ScheduledAt.AddMinutes(a.DurationMinutes) > appointment.ScheduledAt
                && a.PetId == appointment.PetId);

        if (hasConflict)
        {
            conflictWarning = "Warning: This pet already has an overlapping appointment at this time.";
        }

        try
        {
            if (Id.HasValue)
            {
                DbContext.Appointments.Update(appointment);
            }
            else
            {
                appointment.CreatedAt = DateTime.UtcNow;
                DbContext.Appointments.Add(appointment);
            }

            await DbContext.SaveChangesAsync();
            successMessage = Id.HasValue ? "Appointment updated." : "Appointment created.";
            if (!Id.HasValue)
            {
                Navigation.NavigateTo("/appointments");
            }
        }
        catch (Exception ex)
        {
            errorMessage = $"Error: {ex.Message}";
        }
    }

    private async Task CancelAppointment()
    {
        appointment.Status = AppointmentStatus.Cancelled;
        DbContext.Appointments.Update(appointment);
        await DbContext.SaveChangesAsync();
        successMessage = "Appointment cancelled.";
    }
}

