@code {
    private List<Invoice>? allInvoices;
    private List<Invoice>? filteredInvoices;
    private string statusFilter = "";
    private string searchTerm = "";

    protected override async Task OnInitializedAsync()
    {
        allInvoices = await DbContext.Invoices
            .Include(i => i.Owner)
            .OrderByDescending(i => i.InvoiceDate)
            .ToListAsync();
        ApplyFilter();
    }

    private void ApplyFilter()
    {
        if (allInvoices == null) return;

        var query = allInvoices.AsEnumerable();

        if (!string.IsNullOrWhiteSpace(statusFilter) && Enum.TryParse<InvoiceStatus>(statusFilter, out var status))
        {
            query = query.Where(i => i.Status == status);
        }

        if (!string.IsNullOrWhiteSpace(searchTerm))
        {
            var term = searchTerm.ToLower();
            query = query.Where(i =>
                (i.Owner?.FirstName?.ToLower().Contains(term) ?? false) ||
                (i.Owner?.LastName?.ToLower().Contains(term) ?? false));
        }

        filteredInvoices = query.ToList();
    }

    private string GetStatusBadge(InvoiceStatus status) => status switch
    {
        InvoiceStatus.Pending => "bg-warning text-dark",
        InvoiceStatus.PartiallyPaid => "bg-info",
        InvoiceStatus.Paid => "bg-success",
        InvoiceStatus.Overdue => "bg-danger",
        _ => "bg-secondary"
    };
}

