@code {
    [Parameter] public int? Id { get; set; }

    private Invoice invoice = new() { InvoiceDate = DateTime.Today, DueDate = DateTime.Today.AddDays(30), Status = InvoiceStatus.Pending };
    private List<Owner>? owners;
    private List<Treatment>? ownerTreatments;
    private HashSet<int> selectedTreatmentIds = new();
    private string? errorMessage;
    private string? successMessage;

    protected override async Task OnInitializedAsync()
    {
        owners = await DbContext.Owners.OrderBy(o => o.LastName).ToListAsync();

        if (Id.HasValue)
        {
            var existing = await DbContext.Invoices.FindAsync(Id.Value);
            if (existing == null)
            {
                errorMessage = "Invoice not found.";
                return;
            }
            invoice = existing;
            await LoadOwnerTreatments();
        }
    }

    private async Task LoadOwnerTreatments()
    {
        if (invoice.OwnerId > 0)
        {
            ownerTreatments = await DbContext.Treatments
                .Include(t => t.Pet)
                .Where(t => t.Pet!.OwnerId == invoice.OwnerId && t.Cost > 0)
                .OrderByDescending(t => t.TreatmentDate)
                .ToListAsync();
        }
        else
        {
            ownerTreatments = null;
        }
    }

    private void ToggleTreatment(int treatmentId, bool isChecked)
    {
        if (isChecked)
            selectedTreatmentIds.Add(treatmentId);
        else
            selectedTreatmentIds.Remove(treatmentId);

        // Recalculate total from selected treatments
        if (ownerTreatments != null)
        {
            invoice.TotalAmount = ownerTreatments
                .Where(t => selectedTreatmentIds.Contains(t.Id))
                .Sum(t => t.Cost);
        }
    }

    private async Task HandleSubmit()
    {
        try
        {
            if (Id.HasValue)
            {
                DbContext.Invoices.Update(invoice);
            }
            else
            {
                invoice.CreatedAt = DateTime.UtcNow;
                DbContext.Invoices.Add(invoice);
            }

            await DbContext.SaveChangesAsync();
            successMessage = Id.HasValue ? "Invoice updated." : "Invoice created.";
            if (!Id.HasValue)
            {
                Navigation.NavigateTo($"/billing/{invoice.Id}");
            }
        }
        catch (Exception ex)
        {
            errorMessage = $"Error: {ex.Message}";
        }
    }
}

