@code {
    [Parameter] public int Id { get; set; }

    private Invoice? invoice;
    private List<Payment>? payments;
    private bool showPaymentForm;

    private decimal RemainingBalance => (invoice?.TotalAmount ?? 0) - (invoice?.PaidAmount ?? 0);

    protected override async Task OnInitializedAsync()
    {
        await LoadInvoice();
    }

    private async Task LoadInvoice()
    {
        invoice = await DbContext.Invoices
            .Include(i => i.Owner)
            .FirstOrDefaultAsync(i => i.Id == Id);

        payments = await DbContext.Payments
            .Where(p => p.InvoiceId == Id)
            .OrderByDescending(p => p.PaymentDate)
            .ToListAsync();
    }

    private void TogglePaymentForm()
    {
        showPaymentForm = !showPaymentForm;
    }

    private async Task OnPaymentRecorded()
    {
        showPaymentForm = false;
        await LoadInvoice();
    }

    private string GetStatusBadge(InvoiceStatus status) => status switch
    {
        InvoiceStatus.Pending => "bg-warning text-dark",
        InvoiceStatus.PartiallyPaid => "bg-info",
        InvoiceStatus.Paid => "bg-success",
        InvoiceStatus.Overdue => "bg-danger",
