@code {
    [Parameter] public int? Id { get; set; }
    [SupplyParameterFromQuery(Name = "date")] public string? DateParam { get; set; }

    private Appointment appointment = new() { DurationMinutes = 30, Status = AppointmentStatus.Scheduled };
    private List<Pet>? pets;
    private string? errorMessage;
    private string? successMessage;
    private string? conflictWarning;

    protected override async Task OnInitializedAsync()
    {
        pets = await DbContext.Pets.Include(p => p.Owner).OrderBy(p => p.Name).ToListAsync();

        if (Id.HasValue)
        {
            var existing = await DbContext.Appointments.FindAsync(Id.Value);
            if (existing == null)
            {
                errorMessage = "Appointment not found.";
                return;
            }
            appointment = existing;
        }
        else if (!string.IsNullOrEmpty(DateParam) && DateTime.TryParse(DateParam, out var parsedDate))
        {
            appointment.ScheduledAt = parsedDate;
        }
    }

    private async Task HandleSubmit()
    {
        errorMessage = null;
        successMessage = null;
        conflictWarning = null;

        // Validate no scheduling conflicts
        var endTime = appointment.ScheduledAt.AddMinutes(appointment.DurationMinutes);
        var hasConflict = await DbContext.Appointments
            .AnyAsync(a => a.Id != (Id ?? 0)
                && a.Status != AppointmentStatus.Cancelled
                && a.ScheduledAt < endTime
                && a.ScheduledAt.AddMinutes(a.DurationMinutes) > appointment.ScheduledAt
                && a.PetId == appointment.PetId);

        if (hasConflict)
        {
            conflictWarning = "Warning: This pet already has an overlapping appointment at this time.";
        }

        try
        {
            if (Id.HasValue)
            {
                DbContext.Appointments.Update(appointment);
            }
            else
            {
                appointment.CreatedAt = DateTime.UtcNow;
                DbContext.Appointments.Add(appointment);
            }

            await DbContext.SaveChangesAsync();
            successMessage = Id.HasValue ? "Appointment updated." : "Appointment created.";
            if (!Id.HasValue)
            {
                Navigation.NavigateTo("/appointments");
            }
        }
        catch (Exception ex)
        {
            errorMessage = $"Error: {ex.Message}";
        }
    }

    private async Task CancelAppointment()
    {
        appointment.Status = AppointmentStatus.Cancelled;
        DbContext.Appointments.Update(appointment);
        await DbContext.SaveChangesAsync();
        successMessage = "Appointment cancelled.";
    }
}

