+@code {
+    [Parameter] public int InvoiceId { get; set; }
+    [Parameter] public decimal RemainingBalance { get; set; }
+    [Parameter] public EventCallback OnPaymentRecorded { get; set; }
+
+    private Payment payment = new() { PaymentDate = DateTime.Today, Method = PaymentMethod.Card };
+    private string? errorMessage;
+    private string? successMessage;
+
+    private async Task HandleSubmit()
+    {
+        errorMessage = null;
+        successMessage = null;
+
+        if (payment.Amount <= 0)
+        {
+            errorMessage = "Amount must be greater than zero.";
+            return;
+        }
+
+        if (payment.Amount > RemainingBalance)
+        {
+            errorMessage = "Amount cannot exceed remaining balance.";
+            return;
+        }
+
+        try
+        {
+            payment.InvoiceId = InvoiceId;
+            payment.CreatedAt = DateTime.UtcNow;
+            DbContext.Payments.Add(payment);
+
+            var invoice = await DbContext.Invoices.FindAsync(InvoiceId);
+            if (invoice != null)
+            {
+                invoice.PaidAmount += payment.Amount;
+                if (invoice.PaidAmount >= invoice.TotalAmount)
+                    invoice.Status = InvoiceStatus.Paid;
+                else if (invoice.PaidAmount > 0)
+                    invoice.Status = InvoiceStatus.PartiallyPaid;
+            }
+
+            await DbContext.SaveChangesAsync();
+            successMessage = "Payment recorded.";
+            await OnPaymentRecorded.InvokeAsync();
+        }
+        catch (Exception ex)
+        {
+            errorMessage = $"Error: {ex.Message}";
+        }
+    }
