+@page "/owners"
+@attribute [Authorize]
+@rendermode InteractiveServer
+@using Microsoft.AspNetCore.Authorization
+@using Microsoft.EntityFrameworkCore
+@inject VetClinic.Data.ApplicationDbContext DbContext
+@inject NavigationManager Navigation
+
+<PageTitle>Owners</PageTitle>
+
+<div class="d-flex justify-content-between align-items-center mb-4">
+    <h1>Owners</h1>
+    <a href="/owners/new" class="btn btn-primary">Add Owner</a>
+</div>
+
+<div class="row mb-3">
+    <div class="col-md-6">
+        <input type="text" class="form-control" placeholder="Search by name, email, or phone..."
+               @bind="searchTerm" @bind:event="oninput" @bind:after="FilterOwners" />
+    </div>
+</div>
+
+@if (filteredOwners == null)
+{
+    <p>Loading...</p>
+}
+else if (!filteredOwners.Any())
+{
+    <p class="text-muted">No owners found.</p>
+}
+else
+{
+    <div class="table-responsive">
+        <table class="table table-striped table-hover">
+            <thead>
+                <tr>
+                    <th @onclick="() => SortBy(\"Name\")" style="cursor:pointer">Name ↕</th>
+                    <th>Phone</th>
+                    <th>Email</th>
+                    <th>Pets</th>
+                    <th>Actions</th>
+                </tr>
+            </thead>
+            <tbody>
+                @foreach (var owner in filteredOwners)
+                {
+                    <tr>
+                        <td>@owner.Owner.FirstName @owner.Owner.LastName</td>
+                        <td>@owner.Owner.Phone</td>
+                        <td>@owner.Owner.Email</td>
+                        <td><span class="badge bg-secondary">@owner.PetCount</span></td>
+                        <td>
+                            <a href="/owners/@owner.Owner.Id/edit" class="btn btn-sm btn-outline-secondary">Edit</a>
+                        </td>
+                    </tr>
+                }
+            </tbody>
+        </table>
+    </div>
+}
+
+@code {
+    private List<OwnerWithPetCount>? allOwners;
+    private List<OwnerWithPetCount>? filteredOwners;
+    private string searchTerm = "";
+    private string sortColumn = "Name";
+    private bool sortAscending = true;
+
+    protected override async Task OnInitializedAsync()
+    {
+        allOwners = await DbContext.Owners
+            .Select(o => new OwnerWithPetCount
+            {
+                Owner = o,
+                PetCount = DbContext.Pets.Count(p => p.OwnerId == o.Id)
+            })
+            .ToListAsync();
+        FilterOwners();
+    }
+
+    private void FilterOwners()
+    {
+        if (allOwners == null) return;
+
+        var query = allOwners.AsEnumerable();
+
+        if (!string.IsNullOrWhiteSpace(searchTerm))
+        {
+            var term = searchTerm.ToLower();
+            query = query.Where(o =>
+                (o.Owner.FirstName?.ToLower().Contains(term) ?? false) ||
+                (o.Owner.LastName?.ToLower().Contains(term) ?? false) ||
+                (o.Owner.Email?.ToLower().Contains(term) ?? false) ||
+                (o.Owner.Phone?.ToLower().Contains(term) ?? false));
+        }
+
+        query = sortAscending
+            ? query.OrderBy(o => o.Owner.LastName)
+            : query.OrderByDescending(o => o.Owner.LastName);
+
+        filteredOwners = query.ToList();
+    }
+
+    private void SortBy(string column)
+    {
+        if (sortColumn == column)
+            sortAscending = !sortAscending;
+        else
+        {
+            sortColumn = column;
+            sortAscending = true;
+        }
+        FilterOwners();
+    }
+
+    private class OwnerWithPetCount
+    {
+        public Owner Owner { get; set; } = null!;
+        public int PetCount { get; set; }
+    }
+}
+

